  1→import { RecordId } from "surrealdb";
  2→import type { ExtractedEntity, ExtractedRelationship, OnboardingAction, OnboardingSeedItem } from "../../shared/contracts";
  3→import { buildExtractionComponentBlock } from "../extraction/components";
  4→import { loadAssistantConversationContext, loadConversationGraphContext, loadExtractionConversationContext } from "../extraction/context-loaders";
  5→import { loadBranchChain, loadMessagesWithInheritance } from "./branch-chain";
  6→import { ingestAttachment } from "../extraction/document-ingestion";
  7→import { persistEmbeddings } from "../extraction/embedding-writeback";
  8→import { extractStructuredGraph } from "../extraction/extract-graph";
  9→import { appendExtractedTools, persistExtractionOutput } from "../extraction/persist-extraction";
 10→import type { ConversationRow, GraphEntityRecord, IncomingAttachment, SourceRecord, WorkspaceRow } from "../extraction/types";
 11→import { elapsedMs, logError, logInfo, userFacingError } from "../http/observability";
 12→import { transitionOnboardingState } from "../onboarding/onboarding-state";
 13→import { generateOnboardingAssistantReply } from "../onboarding/onboarding-reply";
 14→import type { ServerDependencies } from "../runtime/types";
 15→import { runOrchestrator } from "./handler";
 16→import { getWorkspaceOwnerRecord } from "../graph/queries";
 17→import { refreshConversationTouchedBy, maybeUpgradeConversationTitle } from "../workspace/conversation-sidebar";
 18→import { loadWorkspaceProjects } from "../workspace/workspace-scope";
 19→
 20→export async function processChatMessage(input: {
 21→  deps: ServerDependencies;
 22→  conversationId: string;
 23→  messageId: string;
 24→  workspaceRecord: RecordId<"workspace", string>;
 25→  userMessageRecord: RecordId<"message", string>;
 26→  userText: string;
 27→  attachment?: IncomingAttachment;
 28→  onboardingAction?: OnboardingAction;
 29→}): Promise<void> {
 30→  const startedAt = performance.now();
 31→  logInfo("chat.message.process.execution.started", "Chat message processing execution started", {
 32→    conversationId: input.conversationId,
 33→    messageId: input.messageId,
 34→    workspaceId: input.workspaceRecord.id as string,
 35→    hasAttachment: input.attachment !== undefined,
 36→  });
 37→
 38→  try {
 39→    const now = new Date();
 40→    const conversationRecord = new RecordId("conversation", input.conversationId);
 41→    const workspace = await input.deps.surreal.select<WorkspaceRow>(input.workspaceRecord);
 42→    if (!workspace) {
 43→      throw new Error("workspace not found");
 44→    }
 45→
 46→    const conversation = await input.deps.surreal.select<ConversationRow>(conversationRecord);
 47→    if (!conversation) {
 48→      throw new Error("conversation not found");
 49→    }
 50→
 51→    // Check if this conversation is a branch and load inherited context
 52→    const branchChain = await loadBranchChain(input.deps.surreal, input.conversationId);
 53→    const isBranch = branchChain.length > 0;
 54→
 55→    let inheritedEntityIds: RecordId[] | undefined;
 56→    let assistantContextRows: Array<{ id: RecordId<"message", string>; role: "user" | "assistant"; text: string; createdAt: Date | string }>;
 57→
 58→    if (isBranch) {
 59→      // For branches, load full message history including inherited messages
 60→      const allMessages = await loadMessagesWithInheritance(input.deps.surreal, input.conversationId, 30);
 61→      assistantContextRows = allMessages
 62→        .map((m) => ({
 63→          id: new RecordId("message", m.id),
 64→          role: m.role,
 65→          text: m.text,
 66→          createdAt: m.createdAt,
 67→        }))
 68→        .slice(-10);
 69→
 70→      // Derive inherited entity IDs from extraction_relations on inherited messages
 71→      const inheritedMsgIds = allMessages
 72→        .filter((m) => m.inherited)
 73→        .map((m) => new RecordId("message", m.id));
 74→
 75→      if (inheritedMsgIds.length > 0) {
 76→        const [entityRows] = await input.deps.surreal
 77→          .query<[Array<{ out: RecordId }>]>(
 78→            "SELECT DISTINCT out FROM extraction_relation WHERE `in` IN $msgIds LIMIT 30;",
 79→            { msgIds: inheritedMsgIds },
 80→          )
 81→          .collect<[Array<{ out: RecordId }>]>();
 82→        inheritedEntityIds = entityRows.map((r) => r.out);
 83→      }
 84→    } else {
 85→      assistantContextRows = await loadAssistantConversationContext(input.deps.surreal, input.conversationId);
 86→    }
 87→
 88→    const extractionConversationContext = await loadExtractionConversationContext({
 89→      surreal: input.deps.surreal,
 90→      conversationId: input.conversationId,
 91→      currentMessageRecord: input.userMessageRecord,
 92→    });
 93→    const extractionGraphContext = await loadConversationGraphContext(
 94→      input.deps.surreal,
 95→      input.conversationId,
 96→      60,
 97→      inheritedEntityIds && inheritedEntityIds.length > 0 ? { inheritedEntityIds } : undefined,
 98→    );
 99→    const workspaceProjects = await loadWorkspaceProjects(input.deps.surreal, input.workspaceRecord);
100→    const workspaceProjectNames = workspaceProjects.map((project) => project.name);
101→    const persistedEntities: ExtractedEntity[] = [];
102→    const persistedRelationships: ExtractedRelationship[] = [];
103→    const seedItems: OnboardingSeedItem[] = [];
104→    const embeddingTargets: Array<{ record: GraphEntityRecord; text: string }> = [];
105→    const extractedTools: string[] = [];
106→    const unresolvedAssigneeNames = new Set<string>();
107→
108→    if (input.attachment) {
109→      const ingestion = await ingestAttachment({
110→        surreal: input.deps.surreal,
111→        extractionModel: input.deps.extractionModel,
112→        embeddingModel: input.deps.embeddingModel,
113→        embeddingDimension: input.deps.config.embeddingDimension,
114→        extractionStoreThreshold: input.deps.config.extractionStoreThreshold,
115→        extractionModelId: input.deps.config.extractionModelId,
116→        workspaceRecord: input.workspaceRecord,
117→        conversationRecord,
118→        userMessageRecord: input.userMessageRecord,
119→        attachment: input.attachment,
120→        workspaceName: workspace.name,
121→        projectNames: workspaceProjectNames,
122→        now,
123→        onChunkResult: (chunkResult) => {
124→          if (chunkResult.entities.length > 0 || chunkResult.relationships.length > 0) {
125→            input.deps.sse.emitEvent(input.messageId, {
126→              type: "extraction",
127→              messageId: input.messageId,
128→              entities: chunkResult.entities,
129→              relationships: chunkResult.relationships,
130→            });
131→          }
132→          if (chunkResult.seeds.length > 0) {
133→            input.deps.sse.emitEvent(input.messageId, {
134→              type: "onboarding_seed",
135→              messageId: input.messageId,
136→              seeds: chunkResult.seeds,
137→            });
138→          }
139→        },
140→      });
141→
142→      persistedEntities.push(...ingestion.entities);
143→      persistedRelationships.push(...ingestion.relationships);
144→      seedItems.push(...ingestion.seeds);
145→      embeddingTargets.push(...ingestion.embeddingTargets);
146→      extractedTools.push(...ingestion.tools);
147→      for (const unresolvedName of ingestion.unresolvedAssigneeNames) {
148→        unresolvedAssigneeNames.add(unresolvedName);
149→      }
150→    }
151→
152→    const textExtraction = await extractStructuredGraph({
153→      extractionModel: input.deps.extractionModel,
154→      conversationHistory: extractionConversationContext.conversationHistory,
155→      currentMessage: extractionConversationContext.currentMessage,
156→      graphContext: extractionGraphContext,
157→      sourceText: input.userText,
158→      onboarding: !workspace.onboarding_complete,
159→      workspaceName: workspace.name,
160→      projectNames: workspaceProjectNames,
161→    });
162→
163→    const textPersistence = await persistExtractionOutput({
164→      surreal: input.deps.surreal,
165→      extractionModel: input.deps.extractionModel,
166→      embeddingModel: input.deps.embeddingModel,
167→      embeddingDimension: input.deps.config.embeddingDimension,
168→      extractionModelId: input.deps.config.extractionModelId,
169→      extractionStoreThreshold: input.deps.config.extractionStoreThreshold,
170→      workspaceRecord: input.workspaceRecord,
171→      sourceRecord: input.userMessageRecord as SourceRecord,
172→      sourceKind: "message",
173→      sourceLabel: input.userText.slice(0, 140),
174→      promptText: input.userText,
175→      output: textExtraction,
176→      sourceMessageRecord: input.userMessageRecord,
177→      extractionHistoryMessageIds: extractionConversationContext.conversationHistory.map((row) => row.id.id as string),
178→      now,
179→    });
180→
181→    persistedEntities.push(...textPersistence.entities);
182→    persistedRelationships.push(...textPersistence.relationships);
183→    seedItems.push(...textPersistence.seeds);
184→    embeddingTargets.push(...textPersistence.embeddingTargets);
185→    extractedTools.push(...textPersistence.tools);
186→    for (const unresolvedName of textPersistence.unresolvedAssigneeNames) {
187→      unresolvedAssigneeNames.add(unresolvedName);
188→    }
189→
190→    const dedupedTools = [...new Set(extractedTools.map((tool) => tool.trim()).filter((tool) => tool.length > 0))];
191→    await appendExtractedTools(input.deps.surreal, input.workspaceRecord, extractedTools, now);
192→
193→    await refreshConversationTouchedBy(input.deps.surreal, conversationRecord);
194→    await maybeUpgradeConversationTitle(input.deps.surreal, conversationRecord);
195→
196→    const onboardingBefore = workspace.onboarding_complete
197→      ? "complete"
198→      : workspace.onboarding_summary_pending
199→        ? "summary_pending"
200→        : "active";
201→
202→    const onboardingAfter = await transitionOnboardingState({
203→      surreal: input.deps.surreal,
204→      workspaceRecord: input.workspaceRecord,
205→      workspace,
206→      onboardingAction: input.onboardingAction,
207→      now,
208→    });
209→
210→    let assistantText = "";
211→    let assistantSuggestions: string[] = [];
212→    const unresolvedAssigneeSuggestions = [...unresolvedAssigneeNames].map(
213→      (name) => `You mentioned ${name} - want to add them to workspace people?`,
214→    );
215→
216→    if (onboardingAfter === "complete") {
217→      const workspaceOwnerRecord = await getWorkspaceOwnerRecord({
218→        surreal: input.deps.surreal,
219→        workspaceRecord: input.workspaceRecord,
220→      });
221→
222→      const graphAwareResponse = await runOrchestrator({
223→        surreal: input.deps.surreal,
224→        model: input.deps.assistantModel,
225→        pmModel: input.deps.pmModel,
226→        embeddingModel: input.deps.embeddingModel,
227→        embeddingDimension: input.deps.config.embeddingDimension,
228→        extractionModelId: input.deps.config.extractionModelId,
229→        conversationRecord,
230→        workspaceRecord: input.workspaceRecord,
231→        currentMessageRecord: input.userMessageRecord,
232→        latestUserText: input.userText,
233→        ...(workspaceOwnerRecord ? { workspaceOwnerRecord } : {}),
234→        ...(inheritedEntityIds && inheritedEntityIds.length > 0 ? { inheritedEntityIds } : {}),
235→        messages: assistantContextRows.map((row) => ({
236→          role: row.role,
237→          text: row.text,
238→        })),
239→        onToken: async (token) => {
240→          input.deps.sse.emitEvent(input.messageId, {
241→            type: "token",
242→            messageId: input.messageId,
243→            token,
244→          });
245→        },
246→      });
247→
248→      assistantText = graphAwareResponse.text.trim();
249→    } else {
250→      const assistantReply = await generateOnboardingAssistantReply({
251→        assistantModel: input.deps.assistantModel,
252→        surreal: input.deps.surreal,
253→        onboardingState: onboardingAfter,
254→        contextRows: assistantContextRows,
255→        latestUserText: input.userText,
256→        workspaceRecord: input.workspaceRecord,
257→        latestEntities: persistedEntities.map((entity) => ({
258→          kind: entity.kind,
259→          text: entity.text,
260→          confidence: entity.confidence,
261→        })),
262→        latestTools: dedupedTools,
263→      });
264→
265→      assistantText = assistantReply.message.trim();
266→      assistantSuggestions = assistantReply.suggestions;
267→
268→      for (const token of assistantText.split(" ")) {
269→        input.deps.sse.emitEvent(input.messageId, {
270→          type: "token",
271→          messageId: input.messageId,
272→          token: `${token} `,
273→        });
274→        await new Promise((resolve) => setTimeout(resolve, 25));
275→      }
276→    }
277→
278→    assistantSuggestions = sanitizeAssistantSuggestions(
279→      [...assistantSuggestions, ...unresolvedAssigneeSuggestions],
280→      3,
281→    );
282→
283→    const summaryBlock = buildExtractionComponentBlock(
284→      persistedEntities,
285→      persistedRelationships,
286→      input.deps.config.extractionDisplayThreshold,
287→    );
288→
289→    if (summaryBlock) {
290→      if (onboardingAfter === "complete") {
291→        const streamChunk = assistantText.length > 0 ? `\n\n${summaryBlock}` : summaryBlock;
292→        for (const token of streamChunk.split(" ")) {
293→          input.deps.sse.emitEvent(input.messageId, {
294→            type: "token",
295→            messageId: input.messageId,
296→            token: `${token} `,
297→          });
298→        }
299→      }
300→
301→      assistantText = assistantText.length > 0 ? `${assistantText}\n\n${summaryBlock}` : summaryBlock;
302→    }
303→
304→    if (assistantText.trim().length === 0) {
305→      assistantText = "I could not generate a response for that request.";
306→    }
307→
308→    const assistantMessageRecord = new RecordId("message", input.messageId);
309→    await input.deps.surreal.create(assistantMessageRecord).content({
310→      conversation: conversationRecord,
311→      role: "assistant",
312→      text: assistantText,
313→      ...(assistantSuggestions.length > 0 ? { suggestions: assistantSuggestions } : {}),
314→      createdAt: now,
315→    });
316→
317→    await input.deps.surreal.update(conversationRecord).merge({
318→      updatedAt: now,
319→    });
320→
321→    void persistEmbeddings({
322→      surreal: input.deps.surreal,
323→      embeddingModel: input.deps.embeddingModel,
324→      embeddingDimension: input.deps.config.embeddingDimension,
325→      assistantMessageRecord,
326→      assistantText,
327→      entities: embeddingTargets,
328→    }).catch(() => undefined);
329→
330→    input.deps.sse.emitEvent(input.messageId, {
331→      type: "extraction",
332→      messageId: input.messageId,
333→      entities: persistedEntities,
334→      relationships: persistedRelationships,
335→    });
336→
337→    if (seedItems.length > 0) {
338→      input.deps.sse.emitEvent(input.messageId, {
339→        type: "onboarding_seed",
340→        messageId: input.messageId,
341→        seeds: seedItems,
342→      });
343→    }
344→
345→    if (onboardingBefore !== onboardingAfter) {
346→      input.deps.sse.emitEvent(input.messageId, {
347→        type: "onboarding_state",
348→        messageId: input.messageId,
349→        onboardingState: onboardingAfter,
350→      });
351→    }
352→
353→    input.deps.sse.emitEvent(input.messageId, {
354→      type: "assistant_message",
355→      messageId: input.messageId,
356→      text: assistantText,
357→      ...(assistantSuggestions.length > 0 ? { suggestions: assistantSuggestions } : {}),
358→    });
359→
360→    input.deps.sse.emitEvent(input.messageId, {
361→      type: "done",
362→      messageId: input.messageId,
363→    });
364→
365→    logInfo("chat.message.process.execution.completed", "Chat message processing execution completed", {
366→      conversationId: input.conversationId,
367→      messageId: input.messageId,
368→      workspaceId: input.workspaceRecord.id as string,
369→      entityCount: persistedEntities.length,
370→      relationshipCount: persistedRelationships.length,
371→      seedCount: seedItems.length,
372→      durationMs: elapsedMs(startedAt),
373→    });
374→  } catch (error) {
375→    logError("chat.message.process.execution.failed", "Chat message processing execution failed", error, {
376→      conversationId: input.conversationId,
377→      messageId: input.messageId,
378→      workspaceId: input.workspaceRecord.id as string,
379→      durationMs: elapsedMs(startedAt),
380→    });
381→    const errorText = userFacingError(error, "chat processing failed");
382→    input.deps.sse.emitEvent(input.messageId, {
383→      type: "error",
384→      messageId: input.messageId,
385→      error: errorText,
386→    });
387→  }
388→}
389→
390→function sanitizeAssistantSuggestions(suggestions: string[], limit: number): string[] {
391→  return [...new Set(suggestions.map((value) => value.trim()))]
392→    .filter((value) => value.length > 0 && value.length <= 140)
393→    .slice(0, limit);
394→}
