 52→    const placeholderExtraction = placeholderEvents.find((event) => event.type === "extraction");
 53→    expect(placeholderExtraction).toBeDefined();
 54→    if (!placeholderExtraction || placeholderExtraction.type !== "extraction") {
 55→      throw new Error("Placeholder turn missing extraction event");
 56→    }
 57→
 58→    const hasPlaceholderProject = placeholderExtraction.entities.some(
 59→      (entity) => entity.kind === "project" && normalizeName(entity.text) === "my project",
 60→    );
 61→    expect(hasPlaceholderProject).toBe(false);
 62→
 63→    const projects = await loadWorkspaceProjects(surreal, workspaceRecord);
 64→    const persistedPlaceholderProject = projects.some((project) => normalizeName(project.name) === "my project");
 65→    expect(persistedPlaceholderProject).toBe(false);
