 85→    const assistantEvent = knownPersonEvents.find((event) => event.type === "assistant_message");
 86→    expect(assistantEvent).toBeDefined();
 87→    if (!assistantEvent || assistantEvent.type !== "assistant_message") {
 88→      throw new Error("Known-person turn missing assistant_message");
 89→    }
