 92→    expect(questionCount).toBe(1);
 93→
 94→    const peopleAfterKnown = await loadWorkspacePeople(surreal, workspaceRecord);
 95→    expect(peopleAfterKnown.length).toBe(initialPeople.length);
 96→  }, 180_000);
 97→});
 98→
 99→async function loadWorkspacePeople(
100→  surreal: Surreal,
101→  workspaceRecord: RecordId<"workspace", string>,
102→): Promise<Array<{ id: RecordId<"person", string>; name: string }>> {
103→  const [rows] = await surreal
104→    .query<[Array<{ id: RecordId<"person", string>; name: string }>]>(
105→      "SELECT id, name FROM person WHERE id IN (SELECT VALUE `in` FROM member_of WHERE out = $workspace);",
106→      {
107→        workspace: workspaceRecord,
108→      },
109→    )
110→    .collect<[Array<{ id: RecordId<"person", string>; name: string }>]>();
111→
112→  return rows;
113→}
114→
115→async function loadWorkspaceProjects(
116→  surreal: Surreal,
117→  workspaceRecord: RecordId<"workspace", string>,
118→): Promise<Array<{ id: RecordId<"project", string>; name: string }>> {
119→  const [rows] = await surreal
120→    .query<[Array<{ id: RecordId<"project", string>; name: string }>]>(
121→      "SELECT id, name FROM project WHERE id IN (SELECT VALUE out FROM has_project WHERE `in` = $workspace);",
122→      {
123→        workspace: workspaceRecord,
124→      },
125→    )
126→    .collect<[Array<{ id: RecordId<"project", string>; name: string }>]>();
127→
128→  return rows;
129→}
