131→async function sendChatAndCollectEvents(
132→  baseUrl: string,
133→  input: {
134→    workspaceId: string;
135→    conversationId: string;
136→    text: string;
137→  },
138→): Promise<StreamEvent[]> {
139→  const message = await fetchJson<{ streamUrl: string }>(`${baseUrl}/api/chat/messages`, {
140→    method: "POST",
141→    headers: { "Content-Type": "application/json" },
142→    body: JSON.stringify({
143→      clientMessageId: randomUUID(),
144→      workspaceId: input.workspaceId,
145→      conversationId: input.conversationId,
146→      text: input.text,
147→    }),
148→  });
149→
150→  return await collectSseEvents<StreamEvent>(`${baseUrl}${message.streamUrl}`, 120_000);
151→}
152→
153→function normalizeName(value: string): string {
154→  return value
155→    .toLowerCase()
156→    .replace(/[^a-z0-9\s]/g, " ")
