 44→  handleWorkspaceBootstrap: (workspaceId: string) => Promise<Response>;
 45→  handleWorkspaceSidebar: (workspaceId: string) => Promise<Response>;
 46→  handleWorkspaceConversation: (workspaceId: string, conversationId: string) => Promise<Response>;
 47→} {
 48→  return {
 49→    handleCreateWorkspace: (request: Request) => handleCreateWorkspace(deps, request),
 50→    handleWorkspaceBootstrap: (workspaceId: string) => handleWorkspaceBootstrap(deps, workspaceId),
 51→    handleWorkspaceSidebar: (workspaceId: string) => handleWorkspaceSidebar(deps, workspaceId),
 52→    handleWorkspaceConversation: (workspaceId: string, conversationId: string) =>
 53→      handleWorkspaceConversation(deps, workspaceId, conversationId),
 54→  };
 55→}
