171→async function handleWorkspaceBootstrap(deps: ServerDependencies, workspaceId: string): Promise<Response> {
172→  const startedAt = performance.now();
173→  logInfo("workspace.bootstrap.started", "Workspace bootstrap started", { workspaceId });
174→
175→  try {
176→    const workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
177→    const workspace = await deps.surreal.select<WorkspaceRow>(workspaceRecord);
178→    if (!workspace) {
179→      throw new HttpError(404, `workspace not found: ${workspaceId}`);
180→    }
181→
182→    const conversationRecord = await resolveWorkspaceBootstrapConversation(deps, workspaceRecord);
183→    const conversationId = conversationRecord.id as string;
184→    const rawMessages = await loadMessagesWithInheritance(deps.surreal, conversationId, 80);
185→
186→    const messages = rawMessages.map((row) => ({
187→      id: row.id,
188→      role: row.role,
189→      text: row.text,
190→      createdAt: toIsoString(row.createdAt),
191→      ...(row.suggestions && row.suggestions.length > 0 ? { suggestions: row.suggestions } : {}),
192→      ...(row.inherited ? { inherited: true } : {}),
193→    } satisfies WorkspaceBootstrapMessage));
194→
195→    const seeds = await loadWorkspaceSeeds(deps, workspaceRecord, 40);
196→    const onboardingState = toOnboardingState(workspace);
197→    const sidebar = await buildWorkspaceConversationSidebar(deps.surreal, workspaceRecord);
198→
199→    const payload: WorkspaceBootstrapResponse = {
200→      workspaceId: workspace.id.id as string,
201→      workspaceName: workspace.name,
202→      onboardingComplete: workspace.onboarding_complete,
203→      onboardingState,
204→      conversationId: conversationRecord.id as string,
205→      messages,
206→      seeds,
207→      sidebar,
208→    };
209→
210→    logInfo("workspace.bootstrap.completed", "Workspace bootstrap completed", {
211→      workspaceId,
212→      conversationId: conversationRecord.id as string,
213→      messageCount: messages.length,
214→      seedCount: seeds.length,
215→      durationMs: elapsedMs(startedAt),
216→    });
217→
218→    return jsonResponse(payload, 200);
219→  } catch (error) {
220→    if (error instanceof HttpError) {
221→      logWarn("workspace.bootstrap.http_error", "Workspace bootstrap failed with client-facing error", {
222→        workspaceId,
223→        statusCode: error.status,
224→      });
225→      return jsonError(error.message, error.status);
226→    }
227→
228→    logError("workspace.bootstrap.failed", "Workspace bootstrap failed", error, { workspaceId });
229→    const errorText = error instanceof Error ? error.message : "workspace bootstrap failed";
230→    return jsonError(errorText, 500);
231→  }
232→}
