388→async function handleWorkspaceConversation(
389→  deps: ServerDependencies,
390→  workspaceId: string,
391→  conversationId: string,
392→): Promise<Response> {
393→  const startedAt = performance.now();
394→  logInfo("workspace.conversation.started", "Workspace conversation request started", {
395→    workspaceId,
396→    conversationId,
397→  });
398→
399→  try {
400→    const workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
401→    const conversationRecord = new RecordId("conversation", conversationId);
402→    const conversation = await deps.surreal.select<{
403→      id: RecordId<"conversation", string>;
404→      workspace: RecordId<"workspace", string>;
405→    }>(conversationRecord);
406→
407→    if (!conversation) {
408→      throw new HttpError(404, `conversation not found: ${conversationId}`);
409→    }
410→
411→    if ((conversation.workspace.id as string) !== (workspaceRecord.id as string)) {
412→      throw new HttpError(400, "conversation does not belong to workspace");
413→    }
414→
415→    const rawMessages = await loadMessagesWithInheritance(deps.surreal, conversationId, 80);
416→
417→    const messages = rawMessages.map((row) => ({
418→      id: row.id,
419→      role: row.role,
420→      text: row.text,
421→      createdAt: toIsoString(row.createdAt),
422→      ...(row.suggestions && row.suggestions.length > 0 ? { suggestions: row.suggestions } : {}),
423→      ...(row.inherited ? { inherited: true } : {}),
424→    } satisfies WorkspaceBootstrapMessage));
425→
426→    const payload: WorkspaceConversationResponse = {
427→      conversationId,
428→      messages,
429→    };
430→
431→    logInfo("workspace.conversation.completed", "Workspace conversation request completed", {
432→      workspaceId,
433→      conversationId,
434→      messageCount: messages.length,
435→      durationMs: elapsedMs(startedAt),
436→    });
437→
438→    return jsonResponse(payload, 200);
439→  } catch (error) {
440→    if (error instanceof HttpError) {
441→      logWarn("workspace.conversation.http_error", "Workspace conversation failed with client-facing error", {
442→        workspaceId,
443→        conversationId,
444→        statusCode: error.status,
445→      });
446→      return jsonError(error.message, error.status);
447→    }
448→
449→    logError("workspace.conversation.failed", "Workspace conversation request failed", error, {
450→      workspaceId,
451→      conversationId,
452→    });
453→    const errorText = error instanceof Error ? error.message : "workspace conversation failed";
454→    return jsonError(errorText, 500);
455→  }
456→}
