332→  async function onSendMessage(
333→    message: string,
334→    options?: { onboardingAction?: OnboardingAction },
335→  ) {
336→    if (isLoading || !workspaceId) {
337→      return;
338→    }
339→
340→    const text = message.trim();
341→    if (!text && !pendingFile) {
342→      return;
343→    }
344→
345→    setErrorMessage(undefined);
346→    setIsLoading(true);
347→    setSuggestions([]);
348→
349→    const clientMessageId = crypto.randomUUID();
350→    const currentAttachment = pendingFile;
351→
352→    setSessions((existing) =>
353→      existing.map((session) =>
354→        session.id === activeSessionId
355→          ? {
356→              ...session,
357→              updatedAt: new Date(),
358→              conversations: [
359→                ...session.conversations,
360→                {
361→                  id: clientMessageId,
362→                  question: text.length > 0 ? text : `Uploaded ${currentAttachment?.name ?? "file"}`,
363→                  createdAt: new Date(),
364→                  ...(currentAttachment
365→                    ? {
366→                        files: [
367→                          {
368→                            name: currentAttachment.name,
369→                            type: currentAttachment.type,
370→                            size: currentAttachment.size,
371→                          },
372→                        ],
373→                      }
374→                    : {}),
375→                },
376→              ],
377→            }
378→          : session,
379→      ),
380→    );
381→
382→    let response: Response;
383→    try {
384→      if (currentAttachment) {
385→        const formData = new FormData();
386→        formData.set("clientMessageId", clientMessageId);
387→        formData.set("workspaceId", workspaceId);
388→        formData.set("text", text);
389→        if (backendConversationId) {
390→          formData.set("conversationId", backendConversationId);
391→        }
392→        if (options?.onboardingAction) {
393→          formData.set("onboardingAction", options.onboardingAction);
394→        }
395→        formData.set("file", currentAttachment);
396→
397→        response = await fetch("/api/chat/messages", {
398→          method: "POST",
399→          body: formData,
400→        });
401→      } else {
402→        response = await fetch("/api/chat/messages", {
403→          method: "POST",
404→          headers: {
405→            "Content-Type": "application/json",
406→          },
407→          body: JSON.stringify({
408→            clientMessageId,
409→            workspaceId,
410→            text,
411→            ...(backendConversationId ? { conversationId: backendConversationId } : {}),
412→            ...(options?.onboardingAction ? { onboardingAction: options.onboardingAction } : {}),
413→          }),
414→        });
415→      }
416→    } catch (error) {
417→      const messageText = error instanceof Error ? error.message : "Network error";
418→      setErrorMessage(messageText);
419→      setIsLoading(false);
420→      return;
421→    } finally {
422→      setPendingFile(undefined);
423→    }
424→
425→    if (!response.ok) {
426→      const body = await response.text();
427→      setErrorMessage(body);
428→      setIsLoading(false);
429→      return;
430→    }
431→
432→    const payload = (await response.json()) as ChatMessageResponse;
433→    const isNewConversation = !backendConversationId;
434→    setBackendConversationId(payload.conversationId);
435→    if (isNewConversation) {
436→      setActiveConversationId(payload.conversationId);
437→    }
438→
439→    if (streamRef.current) {
440→      streamRef.current.close();
441→      streamRef.current = undefined;
442→    }
443→
444→    let streamedText = "";
445→
446→    const stream = new EventSource(payload.streamUrl);
447→    streamRef.current = stream;
448→
449→    stream.onmessage = (messageEvent) => {
450→      const parsed = JSON.parse(messageEvent.data) as ChatStreamEvent;
451→
452→      if (parsed.type === "token") {
453→        streamedText = `${streamedText}${parsed.token}`;
454→        setSessions((existing) =>
455→          existing.map((session) =>
456→            session.id === activeSessionId
457→              ? {
458→                  ...session,
459→                  conversations: session.conversations.map((conversation) =>
460→                    conversation.id === clientMessageId
461→                      ? {
462→                          ...conversation,
463→                          response: streamedText,
464→                          updatedAt: new Date(),
465→                        }
466→                      : conversation,
467→                  ),
468→                }
469→              : session,
470→          ),
471→        );
472→        return;
473→      }
474→
475→      if (parsed.type === "extraction") {
476→        store.mergeSeedItems(
477→          parsed.entities.map((entity) => ({
478→            id: entity.id,
479→            kind: entity.kind,
480→            text: entity.text,
481→            confidence: entity.confidence,
482→            sourceKind: entity.sourceKind,
483→            sourceId: entity.sourceId,
484→          })),
485→        );
486→        return;
487→      }
488→
489→      if (parsed.type === "assistant_message") {
490→        streamedText = parsed.text;
491→        setSuggestions(
492→          (parsed.suggestions ?? []).map((content, index) => ({
493→            id: `suggestion-${parsed.messageId}-${index}-${content}`,
494→            content,
495→          })),
496→        );
497→        setSessions((existing) =>
498→          existing.map((session) =>
499→            session.id === activeSessionId
500→              ? {
501→                  ...session,
502→                  conversations: session.conversations.map((conversation) =>
503→                    conversation.id === clientMessageId
504→                      ? {
505→                          ...conversation,
506→                          response: streamedText,
507→                          updatedAt: new Date(),
508→                        }
509→                      : conversation,
510→                  ),
511→                }
512→              : session,
513→          ),
514→        );
515→        return;
516→      }
517→
518→      if (parsed.type === "onboarding_seed") {
519→        store.mergeSeedItems(parsed.seeds);
520→        return;
521→      }
522→
523→      if (parsed.type === "onboarding_state") {
524→        store.setOnboardingState(parsed.onboardingState);
525→        return;
526→      }
527→
528→      if (parsed.type === "error") {
529→        setErrorMessage(parsed.error);
530→        setIsLoading(false);
531→        stream.close();
532→        streamRef.current = undefined;
533→        return;
534→      }
535→
536→      if (parsed.type === "done") {
537→        setSessions((existing) =>
538→          existing.map((session) =>
539→            session.id === activeSessionId
540→              ? {
541→                  ...session,
542→                  updatedAt: new Date(),
543→                  conversations: session.conversations.map((conversation) =>
544→                    conversation.id === clientMessageId
545→                      ? {
546→                          ...conversation,
547→                          response: streamedText,
548→                          updatedAt: new Date(),
549→                        }
550→                      : conversation,
551→                  ),
552→                }
553→              : session,
554→          ),
555→        );
556→
557→        setIsLoading(false);
558→        stream.close();
559→        streamRef.current = undefined;
560→
561→        // Refresh sidebar after stream completes
562→        if (workspaceId) {
563→          void refreshSidebar(workspaceId);
564→        }
565→      }
566→    };
567→
568→    stream.onerror = () => {
569→      setErrorMessage("SSE stream disconnected");
570→      setIsLoading(false);
571→      stream.close();
572→      streamRef.current = undefined;
573→    };
574→  }
575→
576→  function onStopMessage() {
577→    if (!streamRef.current) {
578→      return;
579→    }
580→
581→    streamRef.current.close();
582→    streamRef.current = undefined;
583→    setIsLoading(false);
584→  }
585→
586→  return {
587→    sessions,
588→    activeSessionId,
589→    activeSession,
590→    activeConversationId,
591→    isLoading,
592→    errorMessage,
593→    suggestions,
594→    pendingFile,
595→    branchingFromId,
596→    inheritedMessageIds,
597→    chatInputRef,
598→    onSendMessage,
599→    onStopMessage,
600→    onNewConversation,
601→    onSelectConversation,
602→    onBranchFromMessage,
603→    searchMentions,
604→    onUploadFile,
605→    onChatInputClickCapture,
606→    setErrorMessage,
607→    refreshSidebar,
608→  };
609→}
