 1→import { RecordId, type Surreal } from "surrealdb";
 2→import type { GraphEntityRecord } from "./types";
 3→
 4→export async function readEntityText(surreal: Surreal, record: GraphEntityRecord): Promise<string | undefined> {
 5→  const table = record.table.name;
 6→
 7→  if (table === "workspace") {
 8→    const row = await surreal.select<{ name: string }>(record as RecordId<"workspace", string>);
 9→    return row?.name;
10→  }
11→
12→  if (table === "project") {
13→    const row = await surreal.select<{ name: string }>(record as RecordId<"project", string>);
14→    return row?.name;
15→  }
16→
17→  if (table === "person") {
18→    const row = await surreal.select<{ name: string }>(record as RecordId<"person", string>);
19→    return row?.name;
20→  }
21→
22→  if (table === "feature") {
23→    const row = await surreal.select<{ name: string }>(record as RecordId<"feature", string>);
24→    return row?.name;
25→  }
26→
27→  if (table === "task") {
28→    const row = await surreal.select<{ title: string }>(record as RecordId<"task", string>);
29→    return row?.title;
30→  }
31→
32→  if (table === "decision") {
33→    const row = await surreal.select<{ summary: string }>(record as RecordId<"decision", string>);
34→    return row?.summary;
35→  }
36→
37→  const row = await surreal.select<{ text: string }>(record as RecordId<"question", string>);
38→  return row?.text;
39→}
