 22→type WorkspaceStateStore = {
 23→  workspaceId?: string;
 24→  workspaceName?: string;
 25→  onboardingComplete: boolean;
 26→  onboardingState?: OnboardingState;
 27→  conversationId?: string;
 28→  sidebar?: WorkspaceConversationSidebarResponse;
 29→  seedItems: OnboardingSeedItem[];
 30→  isBootstrapping: boolean;
 31→  sidebarHandlers?: SidebarHandlers;
 32→  bootstrapPayload?: BootstrapPayload;
 33→
 34→  setWorkspaceId: (workspaceId: string | undefined) => void;
 35→  setWorkspaceName: (name: string) => void;
 36→  setOnboardingState: (state: OnboardingState) => void;
 37→  setConversationId: (id: string | undefined) => void;
 38→  setSidebar: (sidebar: WorkspaceConversationSidebarResponse | undefined) => void;
 39→  setSeedItems: (items: OnboardingSeedItem[]) => void;
 40→  mergeSeedItems: (items: OnboardingSeedItem[]) => void;
 41→  setIsBootstrapping: (value: boolean) => void;
 42→  setSidebarHandlers: (handlers: SidebarHandlers | undefined) => void;
 43→  setBootstrapPayload: (payload: BootstrapPayload | undefined) => void;
 44→  clearWorkspace: () => void;
