 54→export const useWorkspaceState = create<WorkspaceStateStore>((set, get) => ({
 55→  workspaceId: undefined,
 56→  workspaceName: undefined,
 57→  onboardingComplete: false,
 58→  onboardingState: undefined,
 59→  conversationId: undefined,
 60→  sidebar: undefined,
 61→  seedItems: [],
 62→  isBootstrapping: false,
 63→  sidebarHandlers: undefined,
 64→  bootstrapPayload: undefined,
 65→
 66→  setWorkspaceId: (workspaceId) => set({ workspaceId }),
 67→  setWorkspaceName: (name) => set({ workspaceName: name }),
 68→  setOnboardingState: (onboardingState) =>
 69→    set({ onboardingState, onboardingComplete: onboardingState === "complete" }),
 70→  setConversationId: (conversationId) => set({ conversationId }),
 71→  setSidebar: (sidebar) => set({ sidebar }),
 72→  setSeedItems: (seedItems) => set({ seedItems }),
 73→  mergeSeedItems: (items) => {
 74→    const existing = get().seedItems;
 75→    const deduped = new Map(
 76→      existing.map((item) => [`${item.id}:${item.sourceKind}:${item.sourceId}`, item]),
 77→    );
 78→    for (const item of items) {
 79→      const key = `${item.id}:${item.sourceKind}:${item.sourceId}`;
 80→      if (!deduped.has(key)) {
 81→        deduped.set(key, item);
 82→      }
 83→    }
 84→    set({ seedItems: [...deduped.values()] });
 85→  },
 86→  setIsBootstrapping: (isBootstrapping) => set({ isBootstrapping }),
 87→  setSidebarHandlers: (sidebarHandlers) => set({ sidebarHandlers }),
 88→  setBootstrapPayload: (bootstrapPayload) => set({ bootstrapPayload }),
 89→  clearWorkspace: () =>
 90→    set({
 91→      workspaceId: undefined,
 92→      workspaceName: undefined,
 93→      onboardingComplete: false,
 94→      onboardingState: undefined,
 95→      conversationId: undefined,
 96→      sidebar: undefined,
 97→      seedItems: [],
 98→      isBootstrapping: false,
 99→      sidebarHandlers: undefined,
100→      bootstrapPayload: undefined,
101→    }),
102→  applyWorkspace: (ws) =>
103→    set({
104→      workspaceId: ws.id,
105→      workspaceName: ws.name,
106→      onboardingComplete: ws.onboardingComplete,
107→      onboardingState: ws.onboardingState,
108→      conversationId: ws.conversationId,
109→    }),
110→}));
