    content: { text, role: "user", created_at: new Date() },
  });
  return record;
}

async function linkBelongsTo(child: RecordId, parent: RecordId): Promise<void> {
  await surreal.query(
    "RELATE $child->belongs_to->$parent SET added_at = time::now();",
