function buildEntityRecordContent(
  kind: PersistableExtractableEntityKind,
  text: string,
  confidence: number,
  now: Date,
  workspaceRecord: RecordId<"workspace", string>,
  embedding?: number[],
  sourceMessageRecord?: RecordId<"message", string>,
  sourceCommitRecord?: RecordId<"git_commit", string>,
  category?: string,
  priority?: string,
): Record<string, unknown> {
  if (kind === "project") {
    return {
      name: text,
      status: "active",
      ...(embedding ? { embedding } : {}),
      created_at: now,
      updated_at: now,
    };
  }

  if (kind === "feature") {
    return {
      name: text,
      status: "active",
      ...(embedding ? { embedding } : {}),
      created_at: now,
      updated_at: now,
    };
  }

  if (kind === "task") {
    return {
      title: text,
      status: "open",
      extraction_confidence: confidence,
      extracted_at: now,
      ...(sourceMessageRecord ? { source_message: sourceMessageRecord } : {}),
      ...(sourceCommitRecord ? { source_commit: sourceCommitRecord } : {}),
      ...(embedding ? { embedding } : {}),
      ...(category ? { category } : {}),
      ...(priority ? { priority } : {}),
      workspace: workspaceRecord,
      created_at: now,
      updated_at: now,
    };
  }

  if (kind === "decision") {
    return {
      summary: text,
      status: "extracted",
      extraction_confidence: confidence,
      extracted_at: now,
      ...(sourceMessageRecord ? { source_message: sourceMessageRecord } : {}),
      ...(sourceCommitRecord ? { source_commit: sourceCommitRecord } : {}),
      ...(embedding ? { embedding } : {}),
      ...(category ? { category } : {}),
      ...(priority ? { priority } : {}),
      workspace: workspaceRecord,
      created_at: now,
      updated_at: now,
    };
  }

  // question (fallthrough)
  return {
    text,
    status: "open",
    extraction_confidence: confidence,
    extracted_at: now,
    ...(sourceMessageRecord ? { source_message: sourceMessageRecord } : {}),
    ...(sourceCommitRecord ? { source_commit: sourceCommitRecord } : {}),
    ...(embedding ? { embedding } : {}),
    ...(category ? { category } : {}),
    ...(priority ? { priority } : {}),
    workspace: workspaceRecord,
    created_at: now,
    updated_at: now,
  };
}

