145→          text: persisted.text,
146→        });
147→
148→        const descriptionTargets: DescriptionTarget[] = ["project", "feature", "task"];
149→        if (descriptionTargets.includes(persisted.kind as DescriptionTarget)) {
150→          void seedDescriptionEntry({
