152→            targetRecord: persisted.record,
153→            text: extracted.evidence,
154→            source: input.sourceMessageRecord ?? input.sourceCommitRecord ?? input.sourceChunkRecord,
155→          }).catch(() => undefined);
156→        }
157→
158→        if (persisted.kind === "feature") {
159→          void fireDescriptionUpdates({
160→            surreal: input.surreal,
161→            extractionModel: input.extractionModel,
162→            trigger: {
163→              kind: "feature_created",
