205→        to_text: relationship.toText,
206→      }).output("after");
207→
208→      persistedRelationships.push({
209→        id: relationRecord.id as string,
210→        kind: relationship.kind,
211→        fromId: from.id,
212→        toId: to.id,
213→        confidence: relationship.confidence,
