116→  }
117→
118→  const entityRecord = new RecordId(input.extracted.kind, randomUUID()) as GraphEntityRecord;
119→  await input.surreal.create(entityRecord).content(
120→    buildEntityRecordContent(
121→      input.extracted.kind,
122→      input.extracted.text,
123→      input.extracted.confidence,
124→      input.now,
125→      input.workspaceRecord,
126→      candidateEmbedding,
127→      input.sourceMessageRecord,
128→      input.sourceCommitRecord,
129→      input.extracted.category,
130→      input.extracted.priority,
131→    ),
132→  );
133→
134→  await createProvenanceEdge({
135→    surreal: input.surreal,
136→    sourceRecord: input.sourceRecord,
137→    targetRecord: entityRecord,
138→    confidence: input.extracted.confidence,
139→    model: input.extractionModelId,
140→    now: input.now,
141→    fromText: input.extracted.text,
142→    evidence: input.extracted.evidence,
143→    evidenceSourceRecord: input.sourceMessageRecord,
144→    resolvedFromRecord: input.resolvedFromMessageRecord,
145→  });
146→
147→  if (input.extracted.kind === "project") {
148→    await ensureWorkspaceProjectEdge(input.surreal, input.workspaceRecord, entityRecord as RecordId<"project", string>, input.now);
149→    input.workspaceProjects.push({
150→      id: entityRecord as RecordId<"project", string>,
151→      name: input.extracted.text,
152→    });
153→  }
154→
155→  if (input.extracted.kind === "feature") {
156→    const projectRecord = resolveEntityProject(input.extracted.text, input.promptText, input.workspaceProjects);
157→    if (projectRecord) {
158→      await ensureProjectFeatureEdge(input.surreal, projectRecord, entityRecord as RecordId<"feature", string>, input.now);
159→    }
160→  }
161→
162→  if (input.extracted.kind === "task" || input.extracted.kind === "decision" || input.extracted.kind === "question") {
163→    const projectRecord = resolveEntityProject(input.extracted.text, input.promptText, input.workspaceProjects);
164→    if (projectRecord) {
165→      await input.surreal.relate(entityRecord, new RecordId("belongs_to", randomUUID()), projectRecord, {
166→        added_at: input.now,
167→      }).output("after");
168→    }
169→  }
170→
171→  if (bestCandidate && bestSimilarity >= 0.8 && bestSimilarity <= 0.95) {
172→    await input.surreal.relate(entityRecord, new RecordId("entity_relation", randomUUID()), bestCandidate.id, {
173→      kind: "POSSIBLE_DUPLICATE",
174→      confidence: bestSimilarity,
175→      ...(input.sourceMessageRecord ? { source_message: input.sourceMessageRecord } : {}),
176→      ...(input.sourceChunkRecord ? { source_chunk: input.sourceChunkRecord } : {}),
177→      ...(input.sourceCommitRecord ? { source_commit: input.sourceCommitRecord } : {}),
178→      extracted_at: input.now,
179→      created_at: input.now,
180→      from_text: input.extracted.text,
181→      to_text: bestCandidate.text,
182→    }).output("after");
183→  }
184→
185→  return {
186→    record: entityRecord,
187→    text: input.extracted.text,
188→    kind: input.extracted.kind,
189→    created: true,
190→  };
191→}
