260→function buildEntityRecordContent(
261→  kind: PersistableExtractableEntityKind,
262→  text: string,
263→  confidence: number,
264→  now: Date,
265→  workspaceRecord: RecordId<"workspace", string>,
266→  embedding?: number[],
267→  sourceMessageRecord?: RecordId<"message", string>,
268→  sourceCommitRecord?: RecordId<"git_commit", string>,
269→  category?: string,
270→  priority?: string,
271→): Record<string, unknown> {
272→  if (kind === "project") {
273→    return {
274→      name: text,
275→      status: "active",
276→      ...(embedding ? { embedding } : {}),
277→      created_at: now,
278→      updated_at: now,
279→    };
280→  }
281→
282→  if (kind === "feature") {
283→    return {
284→      name: text,
285→      status: "active",
286→      ...(embedding ? { embedding } : {}),
287→      created_at: now,
288→      updated_at: now,
289→    };
290→  }
291→
292→  if (kind === "task") {
293→    return {
294→      title: text,
295→      status: "open",
296→      extraction_confidence: confidence,
297→      extracted_at: now,
298→      ...(sourceMessageRecord ? { source_message: sourceMessageRecord } : {}),
299→      ...(sourceCommitRecord ? { source_commit: sourceCommitRecord } : {}),
300→      ...(embedding ? { embedding } : {}),
301→      ...(category ? { category } : {}),
302→      ...(priority ? { priority } : {}),
303→      workspace: workspaceRecord,
304→      created_at: now,
305→      updated_at: now,
306→    };
307→  }
308→
309→  if (kind === "decision") {
310→    return {
311→      summary: text,
312→      status: "extracted",
313→      extraction_confidence: confidence,
314→      extracted_at: now,
315→      ...(sourceMessageRecord ? { source_message: sourceMessageRecord } : {}),
316→      ...(sourceCommitRecord ? { source_commit: sourceCommitRecord } : {}),
317→      ...(embedding ? { embedding } : {}),
318→      ...(category ? { category } : {}),
319→      ...(priority ? { priority } : {}),
320→      workspace: workspaceRecord,
321→      created_at: now,
322→      updated_at: now,
323→    };
324→  }
325→
326→  // question (fallthrough)
327→  return {
328→    text,
329→    status: "open",
330→    extraction_confidence: confidence,
331→    extracted_at: now,
332→    ...(sourceMessageRecord ? { source_message: sourceMessageRecord } : {}),
333→    ...(sourceCommitRecord ? { source_commit: sourceCommitRecord } : {}),
334→    ...(embedding ? { embedding } : {}),
335→    ...(category ? { category } : {}),
336→    ...(priority ? { priority } : {}),
337→    workspace: workspaceRecord,
338→    created_at: now,
339→    updated_at: now,
340→  };
341→}
