343→export async function loadWorkspaceKindCandidates(
344→  surreal: Surreal,
345→  workspaceRecord: RecordId<"workspace", string>,
346→  kind: ExtractableEntityKind,
347→): Promise<CandidateEntityRow[]> {
348→  if (kind === "project") {
349→    const [rows] = await surreal
350→      .query<[CandidateEntityRow[]]>(
351→        "SELECT id, name AS text, embedding FROM project WHERE id IN (SELECT VALUE out FROM has_project WHERE `in` = $workspace);",
352→        { workspace: workspaceRecord },
353→      )
354→      .collect<[CandidateEntityRow[]]>();
355→    return rows;
356→  }
357→
358→  if (kind === "person") {
359→    const [rows] = await surreal
360→      .query<[CandidateEntityRow[]]>(
361→        "SELECT id, name AS text, embedding FROM person WHERE id IN (SELECT VALUE `in` FROM member_of WHERE out = $workspace);",
362→        { workspace: workspaceRecord },
363→      )
364→      .collect<[CandidateEntityRow[]]>();
365→    return rows;
366→  }
367→
368→  if (kind === "feature") {
369→    const [rows] = await surreal
370→      .query<[CandidateEntityRow[]]>(
371→        [
372→          "SELECT id, name AS text, embedding",
373→          "FROM feature",
374→          "WHERE id IN (",
375→          "  SELECT VALUE out",
376→          "  FROM has_feature",
377→          "  WHERE `in` IN (SELECT VALUE out FROM has_project WHERE `in` = $workspace)",
378→          ");",
379→        ].join(" "),
380→        { workspace: workspaceRecord },
381→      )
382→      .collect<[CandidateEntityRow[]]>();
383→    return rows;
384→  }
385→
386→  if (kind === "task") {
387→    const [rows] = await surreal
388→      .query<[CandidateEntityRow[]]>(
389→        "SELECT id, title AS text, embedding FROM task WHERE workspace = $workspace;",
390→        { workspace: workspaceRecord },
391→      )
392→      .collect<[CandidateEntityRow[]]>();
393→    return rows;
394→  }
395→
396→  if (kind === "decision") {
397→    const [rows] = await surreal
398→      .query<[CandidateEntityRow[]]>(
399→        "SELECT id, summary AS text, embedding FROM decision WHERE workspace = $workspace;",
400→        { workspace: workspaceRecord },
401→      )
402→      .collect<[CandidateEntityRow[]]>();
403→    return rows;
404→  }
405→
406→  const [rows] = await surreal
407→    .query<[CandidateEntityRow[]]>(
408→      "SELECT id, text AS text, embedding FROM question WHERE workspace = $workspace;",
409→      { workspace: workspaceRecord },
410→    )
411→    .collect<[CandidateEntityRow[]]>();
412→  return rows;
413→}
