415→export async function appendWorkspaceTools(
416→  surreal: Surreal,
417→  workspaceRecord: RecordId<"workspace", string>,
418→  toolsToAdd: string[],
419→  now: Date,
420→): Promise<void> {
421→  const [rows] = await surreal
422→    .query<[Array<{ tools?: string[] }>]>("SELECT tools FROM $workspace LIMIT 1;", {
423→      workspace: workspaceRecord,
424→    })
425→    .collect<[Array<{ tools?: string[] }>]>();
426→
427→  const existingTools = rows[0]?.tools ?? [];
428→  const merged = [...new Set([...existingTools, ...toolsToAdd])];
429→  await surreal.update(workspaceRecord).merge({
430→    tools: merged,
431→    updated_at: now,
432→  });
433→}
