435→export function normalizeRelationshipKind(value: string): string {
436→  return value
437→    .trim()
438→    .replace(/[^a-zA-Z0-9]+/g, "_")
439→    .replace(/_+/g, "_")
440→    .replace(/^_/, "")
441→    .replace(/_$/, "")
442→    .toUpperCase();
