445→function cosineSimilarity(a: number[], b: number[]): number {
446→  if (a.length !== b.length) {
447→    return -1;
448→  }
449→
450→  let dot = 0;
451→  let normA = 0;
452→  let normB = 0;
453→
454→  for (let i = 0; i < a.length; i += 1) {
455→    dot += a[i] * b[i];
456→    normA += a[i] * a[i];
457→    normB += b[i] * b[i];
458→  }
459→
460→  if (normA === 0 || normB === 0) {
461→    return -1;
462→  }
463→
464→  return dot / (Math.sqrt(normA) * Math.sqrt(normB));
465→}
