 10→export async function ingestAttachment(input: {
 11→  surreal: Surreal;
 12→  extractionModel: any;
 13→  embeddingModel: any;
 14→  embeddingDimension: number;
 15→  extractionStoreThreshold: number;
 16→  extractionModelId: string;
 17→  workspaceRecord: RecordId<"workspace", string>;
 18→  conversationRecord: RecordId<"conversation", string>;
 19→  userMessageRecord: RecordId<"message", string>;
 20→  attachment: IncomingAttachment;
 21→  workspaceName?: string;
 22→  projectNames?: string[];
 23→  now: Date;
 24→  onChunkResult?: (result: PersistExtractionResult) => void;
 25→}): Promise<PersistExtractionResult> {
 26→  const startedAt = performance.now();
 27→  const documentRecord = new RecordId("document", randomUUID());
 28→  const workspaceId = input.workspaceRecord.id as string;
 29→  const conversationId = input.conversationRecord.id as string;
 30→
 31→  logInfo("attachment.ingest.started", "Attachment ingestion started", {
 32→    workspaceId,
 33→    conversationId,
 34→    documentId: documentRecord.id as string,
 35→    fileSizeBytes: input.attachment.sizeBytes,
 36→  });
 37→
 38→  try {
 39→    await input.surreal.create(documentRecord).content({
 40→      workspace: input.workspaceRecord,
 41→      name: input.attachment.fileName,
 42→      mime_type: input.attachment.mimeType,
 43→      size_bytes: input.attachment.sizeBytes,
 44→      uploaded_at: input.now,
 45→    });
 46→
 47→    const chunks = splitDocumentIntoChunks(input.attachment.content);
 48→    const persistedEntities = [];
 49→    const persistedRelationships = [];
 50→    const seeds = [];
 51→    const embeddingTargets = [];
 52→    const tools = [];
 53→    const unresolvedAssigneeNames = [];
 54→
 55→    for (const chunk of chunks) {
 56→      const chunkRecord = new RecordId("document_chunk", randomUUID());
 57→      const chunkEmbedding = await createEmbedding(input.embeddingModel, input.embeddingDimension, chunk.content);
 58→
 59→      await input.surreal.create(chunkRecord).content({
 60→        document: documentRecord,
 61→        workspace: input.workspaceRecord,
 62→        content: chunk.content,
 63→        ...(chunk.heading ? { section_heading: chunk.heading } : {}),
 64→        position: chunk.position,
 65→        ...(chunkEmbedding ? { embedding: chunkEmbedding } : {}),
 66→        created_at: input.now,
 67→      });
 68→
 69→      const extraction = await extractStructuredGraph({
 70→        extractionModel: input.extractionModel,
 71→        conversationHistory: [],
 72→        graphContext: [],
 73→        sourceText: chunk.content,
 74→        onboarding: true,
 75→        heading: chunk.heading,
 76→        workspaceName: input.workspaceName,
 77→        projectNames: input.projectNames,
 78→      });
 79→
 80→      const result = await persistExtractionOutput({
 81→        surreal: input.surreal,
 82→        extractionModel: input.extractionModel,
 83→        embeddingModel: input.embeddingModel,
 84→        embeddingDimension: input.embeddingDimension,
 85→        extractionModelId: input.extractionModelId,
 86→        extractionStoreThreshold: input.extractionStoreThreshold,
 87→        workspaceRecord: input.workspaceRecord,
 88→        sourceRecord: chunkRecord as SourceRecord,
 89→        sourceKind: "document_chunk",
 90→        sourceLabel: chunk.heading ? `${input.attachment.fileName} · ${chunk.heading}` : input.attachment.fileName,
 91→        promptText: chunk.content,
 92→        output: extraction,
 93→        sourceChunkRecord: chunkRecord,
 94→        now: input.now,
 95→      });
 96→
 97→      input.onChunkResult?.(result);
 98→
 99→      persistedEntities.push(...result.entities);
100→      persistedRelationships.push(...result.relationships);
101→      seeds.push(...result.seeds);
102→      embeddingTargets.push(...result.embeddingTargets);
103→      tools.push(...result.tools);
104→      unresolvedAssigneeNames.push(...result.unresolvedAssigneeNames);
105→    }
106→
107→    logInfo("attachment.ingest.completed", "Attachment ingestion completed", {
108→      workspaceId,
109→      conversationId,
110→      documentId: documentRecord.id as string,
111→      entityCount: persistedEntities.length,
112→      relationshipCount: persistedRelationships.length,
113→      chunkCount: chunks.length,
114→      durationMs: elapsedMs(startedAt),
115→    });
116→
117→    return {
118→      entities: persistedEntities,
119→      relationships: persistedRelationships,
120→      seeds,
121→      embeddingTargets,
122→      tools,
123→      unresolvedAssigneeNames,
124→    };
125→  } catch (error) {
126→    logError("attachment.ingest.failed", "Attachment ingestion failed", error, {
127→      workspaceId,
128→      conversationId,
129→      documentId: documentRecord.id as string,
130→      durationMs: elapsedMs(startedAt),
131→    });
132→    throw error;
133→  }
134→}
