 54→export async function ensureWorkspaceProjectEdge(
 55→  surreal: Surreal,
 56→  workspaceRecord: RecordId<"workspace", string>,
 57→  projectRecord: RecordId<"project", string>,
 58→  now: Date,
 59→): Promise<void> {
 60→  const [edgeRows] = await surreal
 61→    .query<[HasProjectRow[]]>(
 62→      "SELECT id FROM has_project WHERE `in` = $workspace AND out = $project LIMIT 1;",
 63→      {
 64→        workspace: workspaceRecord,
 65→        project: projectRecord,
 66→      },
 67→    )
 68→    .collect<[HasProjectRow[]]>();
 69→
 70→  if (edgeRows.length === 0) {
 71→    await surreal.relate(workspaceRecord, new RecordId("has_project", randomUUID()), projectRecord, {
 72→      added_at: now,
 73→    }).output("after");
 74→  }
 75→}
