100→export async function resolveWorkspaceRecord(
101→  surreal: Surreal,
102→  workspaceId: string,
103→): Promise<RecordId<"workspace", string>> {
104→  const workspaceRecord = new RecordId("workspace", workspaceId);
105→  const workspace = await surreal.select<{ id: RecordId<"workspace", string> }>(workspaceRecord);
106→  if (!workspace) {
107→    throw new HttpError(404, `workspace not found: ${workspaceId}`);
