description:
  "Create a task, feature, or project directly in the knowledge graph. Use when the user explicitly requests creation (\"add a task for X\") or during onboarding entity seeding. For uncertain/brainstormed items, prefer suggest_work_items instead.",
inputSchema: z.object({
  kind: z.enum(["task", "feature", "project"]).describe(
    "task: concrete executable work with action verb. feature: capability/requirement within a project. project: named top-level workstream.",
  ),
  title: z.string().min(1).describe("Concise entity title"),
  rationale: z.string().min(1).describe("Why this entity is needed — seeds the description"),
  category: z.enum(ENTITY_CATEGORIES).optional().describe("Category classification"),
  priority: z.string().optional().describe("Priority: critical, high, medium, low"),
  project: z.string().optional().describe("Project name to scope the entity under"),
}),
execute: async (input, options) => {
  const context = requireToolContext(options);
  const now = new Date();

return tool({
  description:
    "Create a question entity for open questions that require a choice or pending decision — e.g. \"should we use X or Y?\", \"which approach for Z?\". Do NOT use for informational queries like \"what is blocking X?\" or \"how does Y work?\" — answer those directly or use other tools.",
  inputSchema: z.object({
    text: z.string().min(1).describe("The question text"),
    category: z.enum(ENTITY_CATEGORIES).optional().describe("Question category"),
    priority: z.string().optional().describe("Priority: critical, high, medium, low"),
    context: z
      .object({
        project: z.string().optional(),
        feature: z.string().optional(),
      })
      .optional(),
    assigned_to: z.string().optional().describe("Person name to assign the question to"),
  }),

    z.object({
      kind: z.enum(["task", "feature", "project"]).describe("Work item kind"),
      title: z.string().min(1).describe("Concise work item title"),
      rationale: z.string().min(1).describe("Why this work item is needed"),
      category: z.enum(ENTITY_CATEGORIES).optional().describe("Optional work item category"),
      project: z.string().optional().describe("Optional project scope"),
      priority: z.string().optional().describe("Optional priority hint"),
    }),
  ).min(1).max(25),
}),
execute: async (input, options) => {
  const context = requireToolContext(options);

const acceptWorkItemSchema = z.object({
  kind: z.enum(["task", "feature", "project"]),
  title: z.string().min(1),
  rationale: z.string().min(1),
  project: z.string().optional(),
  priority: z.string().optional(),
  category: z.enum(ENTITY_CATEGORIES).optional(),
});

