import { tool } from "ai";
import { z } from "zod";
import { ENTITY_CATEGORIES, type EntityCategory } from "../../../shared/contracts";
import { createEmbeddingVector } from "../../graph/embeddings";
import { resolveWorkspaceProjectRecord, searchEntitiesByEmbedding } from "../../graph/queries";
import { requireToolContext } from "../../chat/tools/helpers";
import type { ChatToolDeps } from "../../chat/tools/types";

type SuggestedWorkItem = {
  kind: "task" | "feature" | "project";
  title: string;
  rationale: string;
  category?: EntityCategory;
  project?: string;
  priority?: string;
  possible_duplicate?: {
    id: string;
    name: string;
    similarity: number;
  };
};

type UpdatedWorkItem = {
  existing_id: string;
  title: string;
  changes: string;
};

type DiscardedWorkItem = {
  title: string;
  reason: string;
};

const CLOSED_STATUSES = new Set(["done", "completed", "closed", "resolved", "superseded"]);

export function createSuggestWorkItemsTool(deps: ChatToolDeps) {
  return tool({
    description:
      "Process a batch of proposed work items and return issue-style PM triage buckets: suggestions, updated, discarded.",
    inputSchema: z.object({
      items: z.array(
        z.object({
          kind: z.enum(["task", "feature", "project"]).describe("Work item kind"),
          title: z.string().min(1).describe("Concise work item title"),
          rationale: z.string().min(1).describe("Why this work item is needed"),
          category: z.enum(ENTITY_CATEGORIES).optional().describe("Optional work item category"),
          project: z.string().optional().describe("Optional project scope"),
          priority: z.enum(ENTITY_PRIORITIES).optional().describe("critical: blocking/urgent. high: important. medium: normal. low: nice-to-have."),
        }),
      ).min(1).max(25),
    }),
    execute: async (input, options) => {
      const context = requireToolContext(options);
      const suggestions: SuggestedWorkItem[] = [];
      const updated: UpdatedWorkItem[] = [];
      const discarded: DiscardedWorkItem[] = [];

      for (const item of input.items) {
        const suggestion: SuggestedWorkItem = {
          kind: item.kind,
          title: item.title,
          rationale: item.rationale,
          ...(item.category ? { category: item.category } : {}),
          ...(item.project ? { project: item.project } : {}),
          ...(item.priority ? { priority: item.priority } : {}),
        };

        const embedding = await createEmbeddingVector(deps.embeddingModel, item.title, deps.embeddingDimension);
        if (!embedding) {
          throw new Error("failed to create embedding for suggest_work_items");
        }

        const projectRecord = item.project
          ? await resolveWorkspaceProjectRecord({
              surreal: deps.surreal,
              workspaceRecord: context.workspaceRecord,
              projectInput: item.project,
            })
          : undefined;

        const candidates = await searchEntitiesByEmbedding({
          surreal: deps.surreal,
          workspaceRecord: context.workspaceRecord,
          queryEmbedding: embedding,
          kinds: [item.kind],
          ...(projectRecord ? { projectRecord } : {}),
          limit: 5,
        });

        const top = candidates[0];
        if (!top) {
          suggestions.push(suggestion);
          continue;
        }

        const normalizedTopStatus = top.status ? top.status.trim().toLowerCase() : undefined;
        if (normalizedTopStatus && CLOSED_STATUSES.has(normalizedTopStatus)) {
          suggestions.push(suggestion);
          continue;
        }

        if (top.score > 0.97) {
          discarded.push({
            title: item.title,
            reason: `Exact duplicate of existing item ${top.kind}:${top.id} (${top.name})`,
          });
          continue;
        }

        if (top.score >= 0.8) {
          updated.push({
            existing_id: `${top.kind}:${top.id}`,
            title: top.name,
            changes: `Merge context from suggested item '${item.title}'`,
          });
          continue;
        }

        suggestions.push(suggestion);
      }

      return {
        suggestions,
        updated,
        discarded,
      };
    },
  });
}

import { generateText, Output, stepCountIs } from "ai";
import { z } from "zod";
import { ENTITY_CATEGORIES, type ExtractedEntity, type ExtractedRelationship } from "../../../shared/contracts";
import type { ChatToolDeps, ChatToolExecutionContext } from "../../chat/tools/types";
import { buildPmSystemPrompt } from "./prompt";
import { createPmTools } from "./tools";

const workItemSuggestionSchema = z.object({
  kind: z.enum(["task", "feature", "project"]),
  title: z.string().min(1),
  rationale: z.string().min(1),
  category: z.enum(ENTITY_CATEGORIES).optional(),
  project: z.string().optional(),
  priority: z.string().optional(),
  possible_duplicate: z
    .object({
      id: z.string().min(1),
      name: z.string().min(1),
      similarity: z.number().min(0).max(1),
    })
    .optional(),
});

const pmAgentResultSchema = z.object({
  summary: z.string().min(1),
  suggestions: z.array(workItemSuggestionSchema),
  updated: z.array(
    z.object({
      existing_id: z.string().min(1),
      title: z.string().min(1),
      changes: z.string().min(1),
    }),
  ),
  discarded: z.array(
    z.object({
      title: z.string().min(1),
      reason: z.string().min(1),
    }),
  ),
  observations_created: z.array(z.string().min(1)),
});

export type WorkItemSuggestion = z.infer<typeof workItemSuggestionSchema>;
export type PmAgentResult = z.infer<typeof pmAgentResultSchema>;

export type PmAgentOutput = PmAgentResult & {
  extracted_entities: ExtractedEntity[];
  extracted_relationships: ExtractedRelationship[];
};

export type PmAgentInput = {
  deps: ChatToolDeps & { pmModel: any };
  context: ChatToolExecutionContext;
  intent: "plan_work" | "check_status" | "organize" | "track_dependencies";
  conversationContext: string;
  project?: string;
};

const INTENT_INSTRUCTIONS: Record<PmAgentInput["intent"], string> = {
  check_status: "Primary action: call get_project_status when a project scope is available.",
  plan_work: "Primary action: propose tasks/features/projects with suggest_work_items or create_work_item, deduping each item.",
  track_dependencies: "Primary action: identify blockers/dependencies and create observations for high-risk paths.",
  organize: "Primary action: organize work into clear, deduplicated next steps.",
};

export async function runPmAgent(input: PmAgentInput): Promise<PmAgentOutput> {
  const system = await buildPmSystemPrompt({
    surreal: input.deps.surreal,
    workspaceRecord: input.context.workspaceRecord,
  });

  const result = await generateText({
    model: input.deps.pmModel,
    system,
    prompt: [
      "You are handling a PM request.",
      `Intent: ${input.intent}`,
      input.project ? `Project hint: ${input.project}` : "Project hint: not provided",
      INTENT_INSTRUCTIONS[input.intent],
      "Context:",
      input.conversationContext,
    ].join("\n"),
    tools: createPmTools(input.deps),
    output: Output.object({ schema: pmAgentResultSchema }),
    experimental_context: input.context,
    stopWhen: stepCountIs(6),
  });

  if (!result.output) {
    throw new Error("pm agent did not produce structured output");
  }

  const extracted_entities: ExtractedEntity[] = [];
  const extracted_relationships: ExtractedRelationship[] = [];

  for (const step of result.steps) {
    for (const toolResult of step.toolResults) {
      const res = toolResult.output as Record<string, unknown> | undefined;
      if (res) {
        if (Array.isArray(res.extracted_entities)) {
          extracted_entities.push(...(res.extracted_entities as ExtractedEntity[]));
        }
        if (Array.isArray(res.extracted_relationships)) {
          extracted_relationships.push(...(res.extracted_relationships as ExtractedRelationship[]));
        }
      }
    }
  }

  return {
    ...result.output,
    extracted_entities,
    extracted_relationships,
  };
}

